import InputForm from "../../Components/Input/InputForm";

function PhotoPage() {
  return (
    <div style={{flex:1, display:"flex", flexDirection:"column", alignItems:"center"}}  
    >
      <header style={{display:"flex",flexDirection:"column", borderBottom:"1px solid #ccc", alignItems:"center", justifyContent:"center"}}>
        <h2 style={{fontWeight:"500"}}>Photo</h2>
        <span style={{marginBottom:"1rem", fontWeight:"100"}}>Add Photo</span>
      </header>
      <div style={{display:"flex", flexDirection:"column"}}>
        <img src="none" alt="image"/>
        <div>
          <InputForm type={"file"} TextPlaceholder={"image"} accept={"image/*"}/>
          <label></label>
        </div>
      </div>

    </div>
  );
}

export default PhotoPage;
